// ─── Storage helpers ──────────────────────────────────────────────────────────
function getProgress(userId) {
  try {
    const raw = localStorage.getItem(`moes_progress_${userId}`);
    return raw ? JSON.parse(raw) : {};
  } catch { return {}; }
}
function saveProgress(userId, progress) {
  try { localStorage.setItem(`moes_progress_${userId}`, JSON.stringify(progress)); } catch {}
  // Mirror to Firestore
  setDoc(doc(db, "users", userId), { progress }, { merge: true }).catch(() => {});
}

// Union-merge two progress-style objects (position/page maps): once a flag is
// true on any device it stays true everywhere, so partial local data on a
// fresh device never regresses progress made elsewhere.
function mergeProgressMaps(local, remote) {
  const merged = { ...(remote || {}), ...(local || {}) };
  for (const key of Object.keys(remote || {})) {
    if (remote[key] === true) merged[key] = true;
  }
  return merged;
}

// Prefer whichever quiz/orientation result passed; otherwise prefer whatever
// exists locally, falling back to the remote copy.
function mergeQuizLikeResult(local, remote) {
  if (local && local.passed) return local;
  if (remote && remote.passed) return remote;
  return local || remote || null;
}

// Pull this user's saved progress down from Firestore and merge it into
// localStorage so logging in on a new device picks up work done elsewhere.
async function syncUserFromCloud(userId) {
  try {
    const snap = await getDoc(doc(db, "users", userId));
    if (!snap.exists()) return getProgress(userId);
    const data = snap.data() || {};

    const mergedProgress = mergeProgressMaps(getProgress(userId), data.progress);
    try { localStorage.setItem(`moes_progress_${userId}`, JSON.stringify(mergedProgress)); } catch {}

    const mergedQuiz = mergeQuizLikeResult(getQuizResult(userId), data.quizResult);
    if (mergedQuiz) { try { localStorage.setItem(`moes_quiz_${userId}`, JSON.stringify(mergedQuiz)); } catch {} }

    const mergedOrientation = mergeQuizLikeResult(getOrientationQuizResult(userId), data.orientationQuizResult);
    if (mergedOrientation) { try { localStorage.setItem(`moes_orientation_quiz_${userId}`, JSON.stringify(mergedOrientation)); } catch {} }

    const mergedNotes = mergeProgressMaps(getOrientationNotes(userId), data.orientationNotes);
    try { localStorage.setItem(`moes_orientation_notes_${userId}`, JSON.stringify(mergedNotes)); } catch {}

    const mergedPositions = mergeProgressMaps(getPositionProgress(userId), data.positionProgress);
    try { localStorage.setItem(`moes_positions_${userId}`, JSON.stringify(mergedPositions)); } catch {}

    return mergedProgress;
  } catch {
    return getProgress(userId);
  }
}

// ─── User Registry (persists across sessions) ─────────────────────────────────
function getAllUsers() {
  try {
    const raw = localStorage.getItem("moes_user_registry");
    return raw ? JSON.parse(raw) : [];
  } catch { return []; }
}
async function getAllUsersFromFirestore() {
  try {
    const snap = await getDocs(collection(db, "users"));
    return snap.docs.map(d => {
      const data = d.data();
      return {
        ...(data.profile || {}),
        progress: data.progress || {},
        quizResult: data.quizResult || null,
        orientationQuizResult: data.orientationQuizResult || null,
        positionProgress: data.positionProgress || {},
      };
    });
  } catch { return []; }
}
function registerUser(user) {
  try {
    const users = getAllUsers();
    const existing = users.findIndex(u => u.id === user.id);
    const record = { ...user, lastSeen: new Date().toLocaleDateString() };
    if (existing >= 0) { users[existing] = { ...users[existing], ...record }; }
    else { users.push({ ...record, joinDate: new Date().toLocaleDateString() }); }
    localStorage.setItem("moes_user_registry", JSON.stringify(users));
  } catch {}
  // Mirror to Firestore
  const profile = { ...user, lastSeen: new Date().toLocaleDateString() };
  getDoc(doc(db, "users", user.id)).then(snap => {
    if (snap.exists()) {
      updateDoc(doc(db, "users", user.id), { profile }).catch(() => {});
    } else {
      setDoc(doc(db, "users", user.id), { profile: { ...profile, joinDate: new Date().toLocaleDateString() }, progress: {}, quizResult: null, orientationQuizResult: null, orientationNotes: {}, positionProgress: {} }).catch(() => {});
    }
  }).catch(() => {});
}
function removeUser(userId) {
  try {
    const users = getAllUsers().filter(u => u.id !== userId);
    localStorage.setItem("moes_user_registry", JSON.stringify(users));
    localStorage.removeItem(`moes_progress_${userId}`);
    localStorage.removeItem(`moes_quiz_${userId}`);
    localStorage.removeItem(`moes_orientation_notes_${userId}`);
    localStorage.removeItem(`moes_positions_${userId}`);
  } catch {}
  deleteDoc(doc(db, "users", userId)).catch(() => {});
}
function resetUserProgress(userId) {
  try {
    localStorage.removeItem(`moes_progress_${userId}`);
    localStorage.removeItem(`moes_quiz_${userId}`);
    localStorage.removeItem(`moes_orientation_quiz_${userId}`);
    localStorage.removeItem(`moes_orientation_notes_${userId}`);
    localStorage.removeItem(`moes_positions_${userId}`);
  } catch {}
  setDoc(doc(db, "users", userId), { progress: {}, quizResult: null, orientationQuizResult: null, orientationNotes: {}, positionProgress: {} }, { merge: true }).catch(() => {});
}
function getUserProgress(userId, embeddedProgress) {
  if (embeddedProgress && Object.keys(embeddedProgress).length > 0) return embeddedProgress;
  return getProgress(userId);
}

